from typing import Optional

# ── Types ────────────────────────────────────────────
Message = dict  # {"role": str, "content": str}

# ── Core Pipeline Class ──────────────────────────────
class ConversationManager:
    """Manages a conversation with a budget cap — common in production AI."""

    def __init__(self, model: str, max_budget_usd: float = 1.0):
        self.model = model
        self.max_budget_usd = max_budget_usd
        self.messages: list[Message] = []
        self.total_tokens_used: int = 0
        self.total_cost_usd: float = 0.0

    def add_message(self, role: str, content: str) -> None:
        if role not in ("user", "assistant", "system"):
            raise ValueError(f"Invalid role: {role}")
        self.messages.append({"role": role, "content": content})

    def estimate_tokens(self, text: str) -> int:
        """Rough estimate: 1 token ≈ 0.75 words."""
        return int(len(text.split()) / 0.75)

    def estimate_cost(self, input_tokens: int, output_tokens: int,
                      price_per_m_in: float = 3.0, price_per_m_out: float = 15.0) -> float:
        return (input_tokens / 1_000_000 * price_per_m_in +
                output_tokens / 1_000_000 * price_per_m_out)

    def record_usage(self, input_tokens: int, output_tokens: int) -> None:
        self.total_tokens_used += input_tokens + output_tokens
        cost = self.estimate_cost(input_tokens, output_tokens)
        self.total_cost_usd += cost

        if self.total_cost_usd > self.max_budget_usd:
            print(f"⚠️  Budget exceeded! ${self.total_cost_usd:.4f} > ${self.max_budget_usd}")

    def get_context_for_api(self) -> list[Message]:
        """Filter system messages to start; user/assistant alternate after."""
        return self.messages

    def summary(self) -> str:
        turns = sum(1 for m in self.messages if m["role"] == "user")
        return (
            f"Model: {self.model} | Turns: {turns} | "
            f"Tokens: {self.total_tokens_used:,} | Cost: ${self.total_cost_usd:.4f}"
        )


# ── Demo ─────────────────────────────────────────────
if __name__ == "__main__":
    mgr = ConversationManager(model="claude-sonnet-4-6", max_budget_usd=0.50)

    mgr.add_message("system", "You are a helpful Python tutor.")
    mgr.add_message("user", "What is a list comprehension?")

    # Simulate API response + usage recording
    fake_response = "A list comprehension is a concise way to create lists: [x*2 for x in range(10)]"
    mgr.add_message("assistant", fake_response)
    mgr.record_usage(input_tokens=45, output_tokens=32)

    mgr.add_message("user", "Give me another example.")
    mgr.add_message("assistant", "Filter even numbers: [x for x in range(20) if x % 2 == 0]")
    mgr.record_usage(input_tokens=90, output_tokens=28)

    # Print all messages using list comprehension
    print("Conversation:")
    print("\n".join(f"  [{m['role'].upper()}]: {m['content'][:60]}" for m in mgr.messages))

    print(f"\n{mgr.summary()}")

    # Dict comprehension: token count per role
    token_by_role = {
        role: sum(mgr.estimate_tokens(m['content'])
                  for m in mgr.messages if m['role'] == role)
        for role in {'user', 'assistant', 'system'}
    }
    print("\nTokens by role:")
    for role, tokens in token_by_role.items():
        print(f"  {role}: ~{tokens} tokens")

