class TokenBudget:
    def __init__(self, daily_limit: int = 100_000):
        self.limit = daily_limit
        self.used = 0
        self.calls: list[dict] = []

    def add_usage(self, input_tokens: int, output_tokens: int) -> None:
        total = input_tokens + output_tokens
        self.used += total
        self.calls.append({"in": input_tokens, "out": output_tokens, "total": total})

    def remaining(self) -> int:
        return max(0, self.limit - self.used)

    def is_over_budget(self) -> bool:
        return self.used > self.limit

    def report(self) -> None:
        pct = self.used / self.limit * 100
        print(f"Budget: {self.used:,} / {self.limit:,} tokens ({pct:.1f}%)")
        print(f"Remaining: {self.remaining():,} | Over budget: {self.is_over_budget()}")
        print("Calls:", [(c['in'], c['out']) for c in self.calls])

# Test
budget = TokenBudget(1000)
for in_t, out_t in [(100, 50), (200, 80), (300, 120), (150, 60), (120, 40)]:
    budget.add_usage(in_t, out_t)
    budget.report()
